#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
namespace Math
{
	inline void exgcd(int a,int b,int &x,int &y)
		{int tmp=x;(b?(exgcd(b,a%b,x,y),tmp=x,x=y,y=tmp-a/b*y):(x=1,y=0));}
	inline int gcd(int x,int y){return y?gcd(y,x%y):x;}
	inline int Inv(int a,int Mod){int x,y;exgcd(a,Mod,x,y);return (x+Mod)%Mod;}
	map<int,int> sav;
	inline int BSGS(int a,int c,int Mod)
	{
//		printf("%lld %lld %lld\n",a,c,Mod);
		sav.clear();
		int T=sqrt(Mod)+1,inva=Inv(a,Mod),buf=1;
		rep(0,T-1,i)
		{
			if(!sav.count(buf*c%Mod))sav[1ll*buf*c%Mod]=i;
			buf=1ll*buf*inva%Mod;
		}
		inva=Inv(buf,Mod);buf=1;
		rep(0,T,i)
		{
			if(sav.count(buf))return i*T+sav[buf];
			buf=1ll*buf*inva%Mod;
		}
//		puts("QwQ?");
		return -1000;
	}
	inline int Solve(int a,int c,int Mod)
	{
//		printf("qwq? %d %d %d\n",a,c,Mod);
		if(a==c)return 1;int GCD=gcd(a,Mod);
		
		if(GCD==1)return BSGS(a,c,Mod);if(c%GCD)return -1000;
		Mod/=GCD;
		int res=Solve(a%Mod,(c/GCD)*Inv(a/GCD,Mod)%Mod,Mod);
		return res+1;
	}
	inline int exBSGS(int a,int c,int Mod){return (c==1)?0:(a?Solve(a,c,Mod):(c?-1:1));}
}
signed main()
{
