		int a=read(),Mod=read(),c=read();if(!a&&!c&&!Mod)break;
		if(Mod==1){puts(((!a)^(!c))?"1":"0");continue;}
		int res=Math::exBSGS(a%Mod,c%Mod,Mod);if(res<0)puts("No Solution");else printf("%lld\n",res);
